def productExceptSelf(nums: List[int]) -> List[int]:
    n = len(nums)
    answer_prefix = [1] * n
    answer_suffix = [1] * n

    #prefix
    running = 1
    for i in range(n):
        answer_prefix[i] = running
        running *= nums[i]

    #sufix
    running = 1
    for j in range(n - 1, -1 , -1):
        answer_suffix[j] = running
        running *= nums[j]

    return [x * y for x, y in zip(answer_prefix, answer_suffix)]

